UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

UPDATE J09A_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT MIN(e."Meter Reading (MR) Doc. No.")
  FROM eablg e
  WHERE e.Installation = J09A_temp.INSTALLATION
);
